import{_ as t,o as d,c as r,ai as i}from"./chunks/framework.LYGRWSbL.js";const m=JSON.parse('{"title":"Les chiffres","description":"","frontmatter":{},"headers":[],"relativePath":"module-1-fondations/chiffres.md","filePath":"module-1-fondations/chiffres.md","lastUpdated":1773302952000}'),s={name:"module-1-fondations/chiffres.md"};function a(n,e,l,o,g,c){return d(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="les-chiffres" tabindex="-1">Les chiffres <a class="header-anchor" href="#les-chiffres" aria-label="Permalink to “Les chiffres”">​</a></h1><p><strong>Prérequis :</strong> <a href="./alphabet-prononciation.html">Alphabet et prononciation</a></p><p><strong>Objectif :</strong> compter de 0 à 1000 et au-dela, comprendre les prix, les âges et les numéros courants.</p><p>Les chiffres allemands suivent une logique très régulière une fois les bases apprises. Le seul piège important : pour les nombres entre 21 et 99, l&#39;allemand dit l&#39;unite avant la dizaine, relie par <em>und</em> (et).</p><h2 id="_0-a-20" tabindex="-1">0 à 20 <a class="header-anchor" href="#_0-a-20" aria-label="Permalink to “0 à 20”">​</a></h2><div class="mt-6 grid grid-cols-4 gap-2"><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">0</div><div class="text-sm text-green-600 font-medium">null</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">1</div><div class="text-sm text-green-600 font-medium">eins</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">2</div><div class="text-sm text-green-600 font-medium">zwei</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">3</div><div class="text-sm text-green-600 font-medium">drei</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">4</div><div class="text-sm text-green-600 font-medium">vier</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">5</div><div class="text-sm text-green-600 font-medium">fünf</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">6</div><div class="text-sm text-green-600 font-medium">sechs</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">7</div><div class="text-sm text-green-600 font-medium">sieben</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">8</div><div class="text-sm text-green-600 font-medium">acht</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">9</div><div class="text-sm text-green-600 font-medium">neun</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">10</div><div class="text-sm text-green-600 font-medium">zehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">11</div><div class="text-sm text-green-600 font-medium">elf</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">12</div><div class="text-sm text-green-600 font-medium">zwölf</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">13</div><div class="text-sm text-green-600 font-medium">dreizehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">14</div><div class="text-sm text-green-600 font-medium">vierzehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">15</div><div class="text-sm text-green-600 font-medium">fünfzehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">16</div><div class="text-sm text-green-600 font-medium">sechzehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">17</div><div class="text-sm text-green-600 font-medium">siebzehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">18</div><div class="text-sm text-green-600 font-medium">achtzehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">19</div><div class="text-sm text-green-600 font-medium">neunzehn</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">20</div><div class="text-sm text-green-600 font-medium">zwanzig</div></div></div><div class="warning custom-block"><p class="custom-block-title">Irréguliers à retenir</p><p>11 (<em>elf</em>) et 12 (<em>zwölf</em>) ne suivent pas la règle. 16 (<em>sechzehn</em>) perd le <em>s</em> de <em>sechs</em>, et 17 (<em>siebzehn</em>) perd le <em>en</em> de <em>sieben</em>.</p></div><h2 id="les-dizaines" tabindex="-1">Les dizaines <a class="header-anchor" href="#les-dizaines" aria-label="Permalink to “Les dizaines”">​</a></h2><div class="mt-4 grid grid-cols-3 gap-3"><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">20</div><div class="text-sm text-green-600 font-medium">zwanzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">30</div><div class="text-sm text-green-600 font-medium">dreißig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">40</div><div class="text-sm text-green-600 font-medium">vierzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">50</div><div class="text-sm text-green-600 font-medium">fünfzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">60</div><div class="text-sm text-green-600 font-medium">sechzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">70</div><div class="text-sm text-green-600 font-medium">siebzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">80</div><div class="text-sm text-green-600 font-medium">achtzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">90</div><div class="text-sm text-green-600 font-medium">neunzig</div></div><div class="p-3 rounded-lg bg-gray-50 border border-gray-100 text-center"><div class="text-lg font-bold text-gray-900">100</div><div class="text-sm text-green-600 font-medium">hundert</div></div></div><div class="warning custom-block"><p class="custom-block-title">Attention à dreißig</p><p>30 s&#39;ecrit <em>dreißig</em> (avec ß). 60 (<em>sechzig</em>) perd le <em>s</em>, 70 (<em>siebzig</em>) perd le <em>en</em>. Même logique que 16 et 17.</p></div><h2 id="les-nombres-composes-21-99" tabindex="-1">Les nombres composes (21-99) <a class="header-anchor" href="#les-nombres-composes-21-99" aria-label="Permalink to “Les nombres composes (21-99)”">​</a></h2><p>En allemand, l&#39;unite vient en premier, puis <em>und</em>, puis la dizaine. C&#39;est l&#39;inverse du français.</p><div class="mt-4 grid gap-3"><div class="flex items-center gap-4 p-4 rounded-lg border border-gray-200"><div class="text-2xl font-bold text-green-600 w-16 shrink-0 text-center">21</div><div><div class="font-medium text-gray-900">einundzwanzig</div><div class="text-sm text-gray-500 mt-1">ein + und + zwanzig - &quot;un-et-vingt&quot;</div></div></div><div class="flex items-center gap-4 p-4 rounded-lg border border-gray-200"><div class="text-2xl font-bold text-green-600 w-16 shrink-0 text-center">35</div><div><div class="font-medium text-gray-900">fünfunddreißig</div><div class="text-sm text-gray-500 mt-1">fünf + und + dreißig - &quot;cinq-et-trente&quot;</div></div></div><div class="flex items-center gap-4 p-4 rounded-lg border border-gray-200"><div class="text-2xl font-bold text-green-600 w-16 shrink-0 text-center">78</div><div><div class="font-medium text-gray-900">achtundsiebzig</div><div class="text-sm text-gray-500 mt-1">acht + und + siebzig - &quot;huit-et-soixante-dix&quot;</div></div></div></div><div class="tip custom-block"><p class="custom-block-title">La règle des nombres composes</p><p><strong>unite + und + dizaine</strong>, le tout en un seul mot. C&#39;est l&#39;inverse du français, on dit &quot;cinq-et-trente&quot; plutot que &quot;trente-cinq&quot;.</p></div><h2 id="les-centaines" tabindex="-1">Les centaines <a class="header-anchor" href="#les-centaines" aria-label="Permalink to “Les centaines”">​</a></h2><table tabindex="0"><thead><tr><th>Nombre</th><th>Allemand</th></tr></thead><tbody><tr><td>100</td><td>hundert</td></tr><tr><td>200</td><td>zweihundert</td></tr><tr><td>350</td><td>dreihundertfünfzig</td></tr><tr><td>1 000</td><td>tausend</td></tr><tr><td>2 000</td><td>zweitausend</td></tr><tr><td>1 500</td><td>tausendfünfhundert</td></tr></tbody></table><p>Les nombres s&#39;ecrivent en un seul mot jusqu&#39;a 999 999.</p><h2 id="utilisation-pratique" tabindex="-1">Utilisation pratique <a class="header-anchor" href="#utilisation-pratique" aria-label="Permalink to “Utilisation pratique”">​</a></h2><p><strong>L&#39;âge</strong> - En allemand on utilisé <em>sein</em> (être) et non <em>avoir</em> :</p><ul><li><em>Ich bin 25 Jahre alt.</em> - J&#39;ai 25 ans.</li><li><em>Wie alt bist du?</em> - Quel âge as-tu ?</li></ul><p><strong>Les prix</strong> - On dit le nombre puis <em>Euro</em> :</p><ul><li><em>Das kostet drei Euro.</em> - Ca coute trois euros.</li><li><em>Das kostet zwanzig Euro fünfzig.</em> - Ca coute vingt euros cinquante.</li></ul><div class="info custom-block"><p class="custom-block-title">Numeros de telephone</p><p>On lit chiffre par chiffre, souvent par paires. Le 0 se dit <em>null</em>. Ex : 06 12 34 56 78 se lit &quot;null sechs, zwölf, vierunddreißig, sechsundfünfzig, achtundsiebzig&quot;.</p></div>',23)])])}const x=t(s,[["render",a]]);export{m as __pageData,x as default};
